const mensagem = $json["mensagem"];
const agentResponse = $('JSON ASSISTANT MENSAGEM2').first().json.content || '';
const abreviacoes = ['Dra.', 'Sr.', 'Sra.', 'Dr.', 'Prof.', '1.', '2.', '3.', '4.'];

// Função para verificar se um caractere é um emoji
const contemEmoji = (texto) => {
  const regexEmoji = /[\uD83C-\uDBFF\uDC00-\uDFFF]+/g;
  return regexEmoji.test(texto);
};

// Regex para identificar pontos de divisão, considerando abreviações
const regex = new RegExp(
  `(?<!\\b(?:${abreviacoes.map(abreviacao => abreviacao.replace('.', '\\.')).join('|')}))(?<=["".!?])\\s+`
);

let partes = mensagem.split(regex);

// Função para verificar se a última palavra de uma frase é uma abreviação
const ultimaPalavraEhAbreviacao = (frase) => {
  const palavras = frase.trim().split(' ');
  const ultimaPalavra = palavras[palavras.length - 1];
  return abreviacoes.includes(ultimaPalavra);
};

// Ajusta a divisão para casos onde a frase termina com uma abreviação
for (let i = 1; i < partes.length; i++) {
  if (ultimaPalavraEhAbreviacao(partes[i - 1])) {
    partes[i - 1] += ' ' + partes[i];
    partes.splice(i, 1);
    i--; // Ajusta o índice após a remoção do elemento
  }
}

// Função para combinar frases curtas em uma única parte
const combinarFrasesCurtas = (partes) => {
  const combinadas = [];
  let buffer = '';

  for (let i = 0; i < partes.length; i++) {
    buffer += partes[i].trim();
    // Combina frases menores que 40 caracteres com a próxima, ou se houver emojis
    if (i < partes.length - 1 && (partes[i].trim().length < 40 || contemEmoji(partes[i].trim()))) {
      buffer += ' ';
    } else {
      combinadas.push(buffer);
      buffer = '';
    }
  }

  if (buffer.length > 0) {
    combinadas.push(buffer);
  }

  return combinadas;
};

partes = combinarFrasesCurtas(partes);

// Função para remover formatação de links
const removerFormatacaoLink = (texto) => {
  const regexLinkFormatado = /\[.*?\]\((.*?)\)/g;
  return texto.replace(regexLinkFormatado, '$1');
};

// Retorna as partes como uma array, removendo partes vazias ou apenas com espaços
const resultado = partes
  .filter(parte => parte.trim() !== '') // Remove partes vazias
  .map(parte => ({ mensagem: removerFormatacaoLink(parte.trim()), agent_response: agentResponse })); // Remove formatação de links e espaços em branco no início e fim

return resultado;

