// Prepara o contexto completo do agent incluindo tools disponíveis
const input = $('When Executed by Another Workflow').item.json;
const agentConfig = $('prompt_agent2').item.json;

const tools_disponiveis = input.tools_disponiveis ?? '';
const tools_json = input.tools_json ?? [];

// Monta bloco de contexto de tools para o prompt
let toolsBlock = '';
if (tools_disponiveis) {
  toolsBlock += `\n\n## TOOLS DISPONÍVEIS NESTE CONTEXTO\nVocê pode chamar APENAS as seguintes tools: ${tools_disponiveis}\nNão invente tools que não estejam nessa lista.`;
}
if (tools_json && tools_json.length > 0) {
  toolsBlock += `\n\n## DESCRIÇÃO DETALHADA DAS TOOLS\n`;
  for (const tool of tools_json) {
    toolsBlock += `\n### ${tool.name}\n`;
    if (tool.label) toolsBlock += `Label: ${tool.label}\n`;
    if (tool.description) toolsBlock += `Descrição: ${tool.description}\n`;
    if (tool.when_to_use) toolsBlock += `Quando usar: ${tool.when_to_use}\n`;
    if (tool.input_schema) toolsBlock += `Parâmetros esperados: ${JSON.stringify(tool.input_schema)}\n`;
  }
}

return [{
  json: {
    role: input.role,
    content: input.content,
    company_id: input.company_id,
    sender_name: input.sender_name ?? '',
    phone: input.message?.phone ?? '',
    tools_disponiveis,
    tools_json,
    tools_context_block: toolsBlock,
    agent: agentConfig
  }
}];

