const ctx   = $('prepara_contexto_agent2').first().json;
const input = $input.first().json;
const company_id      = ctx.company_id      || null;
const contact_id      = ctx.contact_id      || input.contact_id      || null;
const conversation_id = ctx.conversation_id || input.conversation_id || null;
let buffered_user_message = '';
let agent_response = '';
try { buffered_user_message = $('normaliza_input2').first().json.content || ''; } catch(e) {}
try { agent_response = $('Sia One - IA2').first().json.output || ''; } catch(e) {}

// Lê síntese gerada pelo nó sintetiza_conversa_llm1
let sintese = {};
try {
  const rawSintese = $('sintetiza_conversa_llm1').first().json;
  const sintesContent = rawSintese && rawSintese.choices && rawSintese.choices[0] && rawSintese.choices[0].message
    ? rawSintese.choices[0].message.content
    : '{}';
  sintese = JSON.parse(sintesContent);
} catch(e) { sintese = {}; }

const current_time = new Date().toISOString();
const can_create_trigger = !!company_id;

const system_prompt = 'Você é um agente operacional do Sia One responsável por decidir se a conversa deve ser monitorada para follow-up futuro.\n\n'
  + 'Você NÃO envia WhatsApp. Você NÃO cria tarefa diretamente. Você NÃO executa cadência.\n'
  + 'Você recebe a síntese completa da conversa e decide se merece um trigger de follow-up.\n\n'
  + 'Tipos de trigger disponíveis (trigger_type):\n'
  + '- no_response_after_ai_question\n'
  + '- no_response_after_human_message\n'
  + '- third_party_decision_followup\n'
  + '- asked_to_return_later\n'
  + '- qualification_abandoned\n'
  + '- post_quote_followup\n'
  + '- no_followup_needed\n\n'
  + 'Eventos detectados possíveis (detected_event):\n'
  + '- awaiting_contact_reply\n'
  + '- qualification_question_sent\n'
  + '- appointment_question_sent\n'
  + '- quote_sent_waiting_reply\n'
  + '- third_party_decision\n'
  + '- asked_to_return_later\n'
  + '- price_objection\n'
  + '- no_followup_needed\n\n'
  + 'Regras:\n'
  + '- Se a conversa não espera resposta: should_create_trigger = false\n'
  + '- Se confidence < 0.65: should_create_trigger = false\n'
  + '- Use o evento_principal da síntese para guiar o detected_event\n'
  + '- Responda SEMPRE em JSON válido com todos os campos abaixo';

const sintese_str = sintese.resumo
  ? 'Estágio: ' + (sintese.estagio || '?') + '\n'
    + 'Resumo: ' + sintese.resumo + '\n'
    + 'Última ação IA: ' + (sintese.ultima_acao_ia || '?') + '\n'
    + 'Última ação humano: ' + (sintese.ultima_acao_humano || 'nenhuma') + '\n'
    + 'Resposta pendente: ' + (sintese.resposta_pendente_do_contato ? 'SIM' : 'NÃO') + '\n'
    + 'Orçamento enviado: ' + (sintese.orcamento_ou_proposta_enviada ? 'SIM' : 'NÃO') + '\n'
    + 'Pediu para retornar: ' + (sintese.contato_pediu_para_retornar ? 'SIM' : 'NÃO') + '\n'
    + 'Decisor terceiro: ' + (sintese.decisor_terceiro_mencionado ? 'SIM' : 'NÃO') + '\n'
    + 'Engajamento: ' + (sintese.nivel_engajamento || '?') + '\n'
    + 'Objeção: ' + (sintese.objecao_detectada || 'nenhuma') + '\n'
    + 'Evento principal: ' + (sintese.evento_principal || '?')
  : '(síntese não disponível — usando apenas última troca)';

const user_content = 'Momento atual: ' + current_time + '\n\n'
  + '=== SÍNTESE DA CONVERSA ===\n'
  + sintese_str + '\n\n'
  + '=== ÚLTIMA TROCA ===\n'
  + 'Contato: ' + buffered_user_message + '\n'
  + 'IA: ' + agent_response + '\n\n'
  + 'Responda com JSON exatamente neste formato:\n'
  + '{\n'
  + '  "should_create_trigger": true,\n'
  + '  "trigger_type": "no_response_after_ai_question",\n'
  + '  "detected_event": "awaiting_contact_reply",\n'
  + '  "expected_reply_window_minutes": 60,\n'
  + '  "reason": "string",\n'
  + '  "recommended_action": "string",\n'
  + '  "recommended_followup_message": "string",\n'
  + '  "confidence": 0.85,\n'
  + '  "metadata": {}\n'
  + '}';

const llm_payload = {
  model: 'gpt-4.1-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system_prompt },
    { role: 'user',   content: user_content  }
  ]
};

return [{
  json: {
    company_id,
    contact_id,
    conversation_id,
    buffered_user_message,
    agent_response,
    current_time,
    can_create_trigger,
    sintese,
    llm_payload
  }
}];

const raw = $input.first().json;
const prep = $('prepara_followup_decision1').first().json;

let decision = {};
try {
  const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content ? raw.choices[0].message.content : '{}';
  decision = JSON.parse(content);
} catch(e) {
  decision = { should_create_trigger: false, confidence: 0, reason: 'parse_error: ' + e.message };
}

const confidence = parseFloat(decision.confidence || 0);
const shouldCreate = decision.should_create_trigger === true && confidence >= 0.65;
const windowMinutes = parseInt(decision.expected_reply_window_minutes || 1440);
const expectedReplyUntil = new Date(Date.now() + windowMinutes * 60 * 1000).toISOString();

return [{
  json: {
    should_create_trigger: shouldCreate,
    trigger_type: decision.trigger_type || 'no_response_after_ai_question',
    detected_event: decision.detected_event || 'awaiting_contact_reply',
    expected_reply_window_minutes: windowMinutes,
    expected_reply_until: expectedReplyUntil,
    reason: decision.reason || '',
    recommended_action: decision.recommended_action || '',
    recommended_followup_message: decision.recommended_followup_message || '',
    confidence: confidence,
    metadata: decision.metadata || {},
    company_id: prep.company_id,
    contact_id: prep.contact_id,
    conversation_id: prep.conversation_id
  }
}];

const ctx = $('prepara_contexto_agent2').first().json;
const company_id = ctx.company_id || null;
const contact_id = ctx.contact_id || null;
const conversation_id = ctx.conversation_id || null;
let buffered_user_message = '';
let agent_response = '';
try { buffered_user_message = $('normaliza_input2').first().json.content || ''; } catch(e) {}
try { agent_response = $('Sia One - IA2').first().json.output || ''; } catch(e) {}
const allItems = $input.all();
let messages = [];
try {
  if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
    messages = allItems[0].json;
  } else {
    messages = allItems.map(i => i.json).filter(m => m && m.content);
  }
} catch(e) { messages = []; }
messages.sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));
const recent = messages.slice(-15);
const roleLabel = (msg) => {
  const r = (msg.role || '').toLowerCase();
  if (r === 'assistant' || r === 'ai') return 'IA';
  if (r === 'agent' || r === 'human_agent') return 'Agente Humano';
  return 'Contato';
};
const lines = recent.map(msg => {
  const t = msg.created_at
    ? new Date(msg.created_at).toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'})
    : '??:??';
  return '[' + t + '] ' + roleLabel(msg) + ': ' + (msg.content || '').substring(0, 400);
});
if (buffered_user_message) lines.push('[AGORA] Contato: ' + buffered_user_message);
if (agent_response) lines.push('[AGORA] IA: ' + agent_response);
const fullTranscript = lines.join('\n');
const schemaLines = [
  '{',
  '  "estagio": "prospecção|qualificação|proposta|negociação|fechamento|suporte",',
  '  "resumo": "2-3 frases sobre o estado atual",',
  '  "ultima_acao_ia": "o que a IA fez por último",',
  '  "ultima_acao_humano": null,',
  '  "resposta_pendente_do_contato": true,',
  '  "orcamento_ou_proposta_enviada": false,',
  '  "contato_pediu_para_retornar": false,',
  '  "decisor_terceiro_mencionado": false,',
  '  "nivel_engajamento": "alto|médio|baixo|desengajado",',
  '  "objecao_detectada": null,',
  '  "evento_principal": "awaiting_contact_reply|qualification_question_sent|appointment_question_sent|quote_sent_waiting_reply|third_party_decision|asked_to_return_later|price_objection|no_followup_needed"',
  '}'
];
const system_prompt = 'Você é um analista de conversas comerciais. Sintetize o histórico e identifique o estado atual da negociação.\n\nResponda APENAS com JSON neste formato:\n' + schemaLines.join('\n');
const llm_payload = {
  model: 'gpt-4.1-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system_prompt },
    { role: 'user', content: 'Histórico (' + recent.length + ' msgs):\n\n' + (fullTranscript || '(sem histórico)') }
  ]
};
return [{
  json: {
    company_id, contact_id, conversation_id,
    buffered_user_message, agent_response,
    llm_payload, messages_analyzed: recent.length
  }
}];
